        "<h1 class=\"doc-title\">R&amp;R</h1><img class=\"menu-cover\" src=\"Imagenes/R%26R.png\" alt=\"R&amp;R\"><div class=\"menu-list\"><div class=\"menu-chapter\" data-doc=\"rr\" data-sec=\"α\"><span class=\"menu-ch-title\">R&amp;R — Leer</span></div></div>"
